import math
from typing import List

class Solution:
    def minStable(self, nums: List[int], maxC: int) -> int:
        n = len(nums)
        if n == 0:
            return 0

        def possible(target: int) -> bool:
            dp = [0] * (n + 1)
            for i in range(1, n + 1):
                dp[i] = dp[i - 1]
                cnt = 0
                g = 0
                for j in range(i, 0, -1):
                    if g == 0:
                        g = nums[j - 1]
                    else:
                        g = math.gcd(g, nums[j - 1])
                    if g < 2:
                        cnt += 1
                    if cnt > maxC:
                        break
                    if i - j + 1 >= target:
                        dp[i] = max(dp[i], dp[j - 1] + (i - j + 1))
            return dp[n] >= n

        left, right = 1, n
        answer = 0
        while left <= right:
            mid = (left + right) // 2
            if possible(mid):
                answer = mid
                right = mid - 1
            else:
                left = mid + 1
        return answer
